const raw = $input.first().json;
const d = raw.body || raw;

const pedido = d.pedido || {};
const cliente = d.cliente || {};
const comercial = d.comercial || {};
const lineas = Array.isArray(d.lineas) ? d.lineas : [];
const excel = d.excel || null;
const approveUrl = d.approvalUrlApprove || '';
const denyUrl = d.approvalUrlDeny || '';
const emailDirector = d.emailDirector || 'j.deaza@gemavip.com';
const emailCc = d.emailCcResponsable || 'c.betancourt@gmavip.com';
const emailComercial = d.emailComercial || comercial.email || '';

const numPedido = pedido.numero || String(pedido.id || '');
const fecha = pedido.fecha ? new Date(pedido.fecha).toLocaleDateString('es-ES') : '—';
const total = pedido.total != null ? Number(pedido.total).toLocaleString('es-ES', {minimumFractionDigits:2, maximumFractionDigits:2}) + '€' : '—';

const lineasHtml = lineas.map(l => {
  const base = (l.cantidad * l.precio * (1 - (l.dto||0)/100));
  return `<tr><td style="padding:8px 10px;border-bottom:1px solid #e5e5e5;font-size:13px;">${l.codigo||'—'}</td><td style="padding:8px 10px;border-bottom:1px solid #e5e5e5;font-size:13px;">${l.nombre||'—'}</td><td style="padding:8px 10px;border-bottom:1px solid #e5e5e5;font-size:13px;text-align:right;">${l.cantidad}</td><td style="padding:8px 10px;border-bottom:1px solid #e5e5e5;font-size:13px;text-align:right;">${Number(l.precio||0).toFixed(2)}€</td><td style="padding:8px 10px;border-bottom:1px solid #e5e5e5;font-size:13px;text-align:right;">${l.dto ? l.dto+'%' : '—'}</td><td style="padding:8px 10px;border-bottom:1px solid #e5e5e5;font-size:13px;text-align:right;font-weight:600;">${base.toFixed(2)}€</td></tr>`;
}).join('');

const botonesHtml = (approveUrl && denyUrl)
  ? `<table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="margin-top:24px;"><tr><td><a href="${denyUrl}" style="display:inline-block;padding:12px 28px;background:#1f2a44;color:#fff!important;text-decoration:none;border-radius:10px;font-weight:600;font-size:14px;margin-right:12px;">Denegar</a><a href="${approveUrl}" style="display:inline-block;padding:12px 28px;background:#16a34a;color:#fff!important;text-decoration:none;border-radius:10px;font-weight:600;font-size:14px;">Aprobar</a></td></tr></table>`
  : '';

const htmlDirector = `<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"></head>
<body style="margin:0;padding:0;font-family:'Segoe UI',Roboto,Arial,sans-serif;background:#f8f8f8;color:#1f2a44;line-height:1.6;">
<table width="100%" cellpadding="0" cellspacing="0" style="background:linear-gradient(180deg,rgba(0,139,210,0.06) 0%,transparent 120px);">
<tr><td style="padding:40px 20px;"><table width="100%" cellpadding="0" cellspacing="0" style="max-width:640px;margin:0 auto;background:#fff;border-radius:14px;box-shadow:0 10px 30px rgba(12,20,58,0.10);border:1px solid #e5e5e5;">
<tr><td><div style="height:4px;background:linear-gradient(90deg,#008bd2,#2ea3f2,#ffba00,#8fae1b);border-radius:14px 14px 0 0;"></div>
<table width="100%" cellpadding="0" cellspacing="0">
<tr><td style="padding:28px 32px 20px;"><p style="margin:0 0 6px;font-size:12px;color:#5b667a;text-transform:uppercase;letter-spacing:0.5px;">CRM Gemavip · Aprobación de pedido</p><h1 style="margin:0;font-size:22px;font-weight:700;color:#0c143a;">Pedido ${numPedido} pendiente de aprobación</h1><p style="margin:10px 0 0;font-size:13px;color:#5b667a;">Fecha: ${fecha}</p></td></tr>
<tr><td style="padding:0 32px 24px;">
<table width="100%" cellpadding="0" cellspacing="0" style="border:1px solid #e5e5e5;border-radius:14px;overflow:hidden;margin-bottom:20px;">
<tr><td style="padding:20px 24px;background:linear-gradient(135deg,rgba(0,139,210,0.08) 0%,rgba(23,66,139,0.04) 100%);">
<h2 style="margin:0 0 12px;font-size:17px;font-weight:600;color:#0c143a;">Datos del cliente</h2>
<table width="100%" cellpadding="0" cellspacing="0" style="font-size:14px;color:#1f2a44;">
<tr><td style="padding:4px 0;width:130px;color:#5b667a;">Cliente</td><td style="padding:4px 0;font-weight:600;">${cliente.nombre||'—'}</td></tr>
<tr><td style="padding:4px 0;color:#5b667a;">CIF</td><td style="padding:4px 0;">${cliente.cif||'—'}</td></tr>
<tr><td style="padding:4px 0;color:#5b667a;">Dirección</td><td style="padding:4px 0;">${cliente.direccion||'—'}</td></tr>
<tr><td style="padding:4px 0;color:#5b667a;">CP / Población</td><td style="padding:4px 0;">${cliente.cp||''} ${cliente.poblacion||'—'}</td></tr>
<tr><td style="padding:4px 0;color:#5b667a;">Teléfono</td><td style="padding:4px 0;">${cliente.telefono||'—'}</td></tr>
<tr><td style="padding:4px 0;color:#5b667a;">Email</td><td style="padding:4px 0;">${cliente.email||'—'}</td></tr>
</table></td></tr></table>
<table width="100%" cellpadding="0" cellspacing="0" style="border:1px solid #e5e5e5;border-radius:14px;overflow:hidden;margin-bottom:20px;">
<tr><td style="padding:16px 24px;background:#f8f8f8;"><h2 style="margin:0 0 4px;font-size:15px;font-weight:600;color:#0c143a;">Comercial</h2><p style="margin:0;font-size:14px;color:#5b667a;">${comercial.nombre||'—'} · ${comercial.email||'—'}</p></td></tr></table>
<h3 style="margin:0 0 10px;font-size:15px;font-weight:600;color:#0c143a;">Líneas del pedido</h3>
<table width="100%" cellpadding="0" cellspacing="0" style="border:1px solid #e5e5e5;border-radius:10px;overflow:hidden;">
<tr style="background:#f1f5f9;"><th style="padding:10px;font-size:12px;text-align:left;color:#5b667a;">Código</th><th style="padding:10px;font-size:12px;text-align:left;color:#5b667a;">Artículo</th><th style="padding:10px;font-size:12px;text-align:right;color:#5b667a;">Uds</th><th style="padding:10px;font-size:12px;text-align:right;color:#5b667a;">PVL</th><th style="padding:10px;font-size:12px;text-align:right;color:#5b667a;">Dto</th><th style="padding:10px;font-size:12px;text-align:right;color:#5b667a;">Base</th></tr>
${lineasHtml}
</table>
<table width="100%" cellpadding="0" cellspacing="0" style="margin-top:12px;"><tr><td style="text-align:right;font-size:16px;font-weight:700;color:#0c143a;">Total pedido: ${total}</td></tr></table>
${botonesHtml}
</td></tr>
<tr><td style="padding:20px 32px 28px;border-top:1px solid #e5e5e5;"><p style="margin:0;font-size:11px;color:#5b667a;">Correo generado automáticamente por CRM Gemavip</p></td></tr>
</table></td></tr></table></td></tr></table></body></html>`;

const htmlComercial = `<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"></head>
<body style="margin:0;padding:0;font-family:'Segoe UI',Roboto,Arial,sans-serif;background:#f8f8f8;color:#1f2a44;line-height:1.6;">
<table width="100%" cellpadding="0" cellspacing="0" style="background:linear-gradient(180deg,rgba(0,139,210,0.06) 0%,transparent 120px);">
<tr><td style="padding:40px 20px;"><table width="100%" cellpadding="0" cellspacing="0" style="max-width:600px;margin:0 auto;background:#fff;border-radius:14px;box-shadow:0 10px 30px rgba(12,20,58,0.10);border:1px solid #e5e5e5;">
<tr><td><div style="height:4px;background:linear-gradient(90deg,#008bd2,#2ea3f2,#ffba00,#8fae1b);border-radius:14px 14px 0 0;"></div>
<table width="100%" cellpadding="0" cellspacing="0">
<tr><td style="padding:28px 32px 20px;"><p style="margin:0 0 6px;font-size:12px;color:#5b667a;text-transform:uppercase;letter-spacing:0.5px;">CRM Gemavip</p><h1 style="margin:0;font-size:22px;font-weight:700;color:#0c143a;">Pedido ${numPedido} en revisión</h1></td></tr>
<tr><td style="padding:0 32px 24px;"><p style="margin:0 0 16px;font-size:15px;color:#1f2a44;">Tu pedido <strong>${numPedido}</strong> para el cliente <strong>${cliente.nombre||'—'}</strong> ha sido enviado a revisión por la dirección comercial.</p><p style="margin:0 0 8px;font-size:14px;color:#5b667a;">Te notificaremos por email cuando se haya tomado una decisión.</p><table width="100%" cellpadding="0" cellspacing="0" style="margin-top:16px;border:1px solid #e5e5e5;border-radius:10px;overflow:hidden;background:#f8f8f8;"><tr><td style="padding:14px 18px;"><table width="100%" cellpadding="0" cellspacing="0" style="font-size:14px;"><tr><td style="padding:4px 0;color:#5b667a;width:100px;">Pedido</td><td style="padding:4px 0;font-weight:600;">${numPedido}</td></tr><tr><td style="padding:4px 0;color:#5b667a;">Cliente</td><td style="padding:4px 0;">${cliente.nombre||'—'}</td></tr><tr><td style="padding:4px 0;color:#5b667a;">Total</td><td style="padding:4px 0;font-weight:700;">${total}</td></tr><tr><td style="padding:4px 0;color:#5b667a;">Estado</td><td style="padding:4px 0;"><span style="display:inline-block;padding:2px 10px;background:#dbeafe;color:#1e40af;border-radius:6px;font-size:12px;font-weight:600;">Revisando</span></td></tr></table></td></tr></table></td></tr>
<tr><td style="padding:20px 32px 28px;border-top:1px solid #e5e5e5;"><p style="margin:0;font-size:11px;color:#5b667a;">Correo generado automáticamente por CRM Gemavip</p></td></tr>
</table></td></tr></table></td></tr></table></body></html>`;

const outputs = [];

if (emailComercial) {
  outputs.push({
    json: {
      type: 'comercial',
      to: emailComercial,
      subject: `Pedido ${numPedido} en revisión · CRM Gemavip`,
      html: htmlComercial
    }
  });
}

outputs.push({
  json: {
    type: 'director',
    to: emailDirector,
    cc: emailCc,
    subject: `Pedido ${numPedido} · ${cliente.nombre||'Pedido'} · Aprobación · CRM Gemavip`,
    html: htmlDirector,
    excelBase64: excel ? excel.base64 : null,
    excelFilename: excel ? excel.filename : null,
    excelMime: excel ? excel.mime : 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
  }
});

return outputs;

const item = $input.first().json;
const binaryData = {};

if (item.excelBase64) {
  binaryData.attachment = {
    data: item.excelBase64,
    mimeType: item.excelMime || 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
    fileName: item.excelFilename || 'pedido.xlsx'
  };
}

return [{ json: item, binary: binaryData }];
